package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.nio.charset.Charset;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Given
        File file = new File("test.csv");
        Charset charset = Charset.defaultCharset();
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, null, false,
                false, false, false, false);
        CSVPrinter csvPrinterMock = mock(CSVPrinter.class);
        OutputStreamWriter outputStreamWriterMock = mock(OutputStreamWriter.class);

        when(csvPrinterMock.print(any(Appendable.class))).thenReturn(csvPrinterMock);
        when(outputStreamWriterMock.close()).thenReturn(null);
        whenNew(CSVPrinter.class).withArguments(outputStreamWriterMock, csvFormat).thenReturn(csvPrinterMock);
        whenNew(OutputStreamWriter.class).withArguments(new FileOutputStream(file), charset).thenReturn(outputStreamWriterMock);

        // When
        CSVPrinter result = csvFormat.print(file, charset);

        // Then
        assertNotNull(result);
        verifyNew(CSVPrinter.class).withArguments(outputStreamWriterMock, csvFormat);
        verify(outputStreamWriterMock).close();
    }
}
